/*
=========================================================
AGENT BATCH PARSER (v7 - Lineage & Multi-Batch Support)
- Iteriert über ALLE Batches (nicht nur den ersten)
- Extrahiert JSON-Array aus Agenten-String
- Handhabt Markdown-Backticks & Zeilenumbrüche
- Extrahiert die Data Lineage (LLM2, 3 und 4)
=========================================================
*/

const items = $input.all();
const allParsedResults = [];

for (const itemWrapper of items) {
    const item = itemWrapper.json;
    const outputText = item.output || item.text || ""; 

    try {
        // 1. Suche den Start und das Ende des Arrays im String
        const arrayStart = outputText.indexOf('[');
        const arrayEnd = outputText.lastIndexOf(']');

        if (arrayStart === -1 || arrayEnd === -1) {
            allParsedResults.push({
                json: { error: "Kein JSON-Array im Output", raw_output: outputText }
            });
            continue; // Mache mit dem nächsten Batch weiter
        }

        const cleanJsonString = outputText.substring(arrayStart, arrayEnd + 1);
        const agentResults = JSON.parse(cleanJsonString);

        // 2. Jedes Ergebnis im Array als n8n-Item vereinzeln
        for (const res of agentResults) {
            allParsedResults.push({
                json: {
                    // IDs aus dem Flow-Kontext
                    parent_id: item.parent_id || item.ID || "N/A", 

                    // Identifikation
                    keyword_original: res.keyword_original || res.keyword || "N/A",
                    source_cluster: res.source_cluster || "Unsorted",

                    // GND Daten (mit Fallbacks auf alte Nomenklatur)
                    gnd_id: res.gnd_id || null,
                    preferred_name: res.gnd_preferred_name || res.preferred_name || null,
                    confidence: res.gnd_confidence || res.confidence || "no_match",

                    // DATA LINEAGE (Die Begründungen der LLMs)
                    llm2_rationale: res.llm2_rationale || null,
                    llm3_judge_comment: res.llm3_judge_comment || null,
                    llm4_reasoning: res.llm4_reasoning || res.reasoning || null,

                    // Metadaten flachklopfen
                    meta_start_date: res.additional_data?.start_date || null,
                    meta_end_date: res.additional_data?.end_date || null,
                    meta_role: res.additional_data?.role_or_profession || null,
                    meta_location: res.additional_data?.location_primary || null
                }
            });
        }

    } catch (e) {
        // Fehlerfall für diesen spezifischen Batch
        allParsedResults.push({
            json: {
                error: "Parsing Error",
                message: e.message,
                raw_output: outputText
            }
        });
    }
}

return allParsedResults;

/*
=========================================================
FINAL AGGREGATOR (v19 - Post-Parser)
- Aggregiert die vom Parser vereinzelten Items
- Gruppiert nach 'source_cluster'
=========================================================
*/

const items = $input.all();
const enrichedResult = {};

for (const itemWrapper of items) {
    const data = itemWrapper.json;

    // Fehlerhafte Items überspringen
    if (data.error) continue;

    const cluster = data.source_cluster || "Unsorted";
    if (!enrichedResult[cluster]) {
        enrichedResult[cluster] = [];
    }

    // Eintrag zusammenbauen
    const entry = {
        term: data.keyword_original,
        gnd_name: data.preferred_name,
        gnd_id: data.gnd_id,
        confidence: data.confidence,

        // Data Lineage
        llm2_rationale: data.llm2_rationale,
        llm3_judge_comment: data.llm3_judge_comment,
        llm4_reasoning: data.llm4_reasoning,

        // Metadaten (nur falls vorhanden)
        ...(data.meta_start_date && { born_founded: data.meta_start_date }),
        ...(data.meta_end_date && { died_dissolved: data.meta_end_date }),
        ...(data.meta_role && { role_type: data.meta_role }),
        ...(data.meta_location && { location: data.meta_location })
    };

    enrichedResult[cluster].push(entry);
}

return {
    json: {
        gnd_result_string: JSON.stringify(enrichedResult, null, 2)
    }
};

/*
=========================================================
BATCH SPLITTER (FINAL VERSION)
- Gruppiert Keywords in 10er Batches
- Extrahiert 'term', 'why' (rationale) & 'judge_comment' (judge_context)
- Filtert technische Systemfelder aus den Metadaten
- Sichere Fallbacks für Caption & Metadata
=========================================================
*/

const items = $input.all();
const outputBatches = [];
const BATCH_SIZE = 10;

// Felder, die aus den Metadaten gelöscht werden sollen
const excludeKeys = [
    "tags_gemini_2.5_pro",
    "_archived",
    "_creator",
    "_ctime",
    "_last_modifier",
    "_mtime"
];

// Hilfsfunktion zur Reinigung der Metadaten-Strings
function cleanMetadata(rawString) {
    if (!rawString) return "";
    return rawString
        .split('\n')
        .filter(line => !excludeKeys.some(key => line.trim().startsWith(key + ":")))
        .join('\n')
        .trim();
}

const allowedClusters = [
    "Objekttyp", "Thema_Phänomen", "Inhalt_Motiv", "Funktion_Zweck",
    "Visuelle_Merkmale", "Form_Gestalt", "Bestandteile", "Gebrauchskontext",
    "Kultureller_Kontext", "Emotion_Atmosphäre", "Farbe_Nuancen"
];

for (const item of items) {
    const json = item.json;

    // Sichere Fallbacks: Greift alle möglichen Schreibweisen ab
    const rawCaption = json.Caption || json.caption || "";
    const rawMeta = json.Metadata || json.metadata || json.context_data_string || "";

    // Metadaten bereinigen
    const cleanedMeta = cleanMetadata(rawMeta);

    // Keywords und Begründungen sammeln
    const allKeywords = [];
    for (const cluster of allowedClusters) {
        let keywordArray = json[cluster]; 

        if (!keywordArray) continue;

        if (typeof keywordArray === 'string') {
            try { keywordArray = JSON.parse(keywordArray); } catch (e) { keywordArray = []; }
        }

        if (Array.isArray(keywordArray)) {
            keywordArray.forEach(kw => {
                if (kw && kw.term && typeof kw.term === 'string' && kw.term.trim() !== "") {
                    allKeywords.push({
                        keyword: kw.term.trim(),
                        source_cluster: cluster,
                        rationale: kw.why || "",             // Neu: LLM2 Begründung
                        judge_context: kw.judge_comment || "" // Neu: LLM3 Urteil
                    });
                }
            });
        }
    }

    // In 10er Batches aufteilen und Output generieren
    for (let i = 0; i < allKeywords.length; i += BATCH_SIZE) {
        const batchChunk = allKeywords.slice(i, i + BATCH_SIZE);

        outputBatches.push({
            json: {
                keyword_batch: batchChunk, 
                caption: rawCaption,    
                metadata: cleanedMeta,  
                batch_info: {
                    current: Math.floor(i / BATCH_SIZE) + 1,
                    total: Math.ceil(allKeywords.length / BATCH_SIZE)
                }
            }
        });
    }
}

return outputBatches;

